SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW view_fin_tax_fin (tax_date, tax_seq, id_card, prename, memname, memsurname, paid_amount, tax_amount, company_id, vourcher_no, seq_no) AS SELECT sc_fin_vourcher_head.journal_date AS TAX_DATE
  ,row_number() OVER () AS TAX_SEQ
  ,sc_mem_m_membership_registered.id_card AS ID_CARD
  ,sc_mem_m_ucf_prename.prename AS PRENAME
  ,sc_mem_m_membership_registered.member_name AS MEMNAME
  ,sc_mem_m_membership_registered.member_surname AS MEMSURNAME
  ,sc_fin_vourcher_detail.item_amount AS PAID_AMOUNT
  ,0.00 AS TAX_AMOUNT
  
  ,sc_fin_vourcher_head.company_id AS COMPANY_ID
  ,sc_fin_vourcher_head.vourcher_no AS VOURCHER_NO
  ,sc_fin_vourcher_detail.seq_no AS SEQ_NO
    FROM sc_fin_vourcher_head,   
         sc_fin_vourcher_detail,   
         sc_mem_m_membership_registered,   
         sc_mem_m_ucf_prename  
   WHERE ( sc_fin_vourcher_head.vourcher_no = sc_fin_vourcher_detail.vourcher_no ) and ( sc_fin_vourcher_detail.ref_memno = sc_mem_m_membership_registered.membership_no ) and ( sc_mem_m_membership_registered.prename_code = sc_mem_m_ucf_prename.prename_code ) and ( sc_fin_vourcher_detail.account_id in ( '524030' ) )
          
and sc_fin_vourcher_head.cancel_status ='0'
and sc_fin_vourcher_head.post_journal = '1'

--AND TAX_DATE = '26/5/2023'
 

ORDER BY sc_fin_vourcher_head.journal_date ASC
,sc_fin_vourcher_head.vourcher_no 
,sc_fin_vourcher_detail.seq_no;

